"use client";

import { supabase } from "./supabaseClient";
import { DEFAULT_DEMO_USER_ID, normalizeUserId } from "./userIdentity";

export async function ensureClientUserId() {
  if (typeof window !== "undefined") {
    const cached = normalizeUserId(localStorage.getItem("demoUserId"));
    if (cached) {
      return cached;
    }
  }

  const { data, error } = await supabase.auth.getUser();
  const derived = !error ? data?.user?.id || data?.user?.user_metadata?.demoUserId : null;
  const fallback = normalizeUserId(derived, DEFAULT_DEMO_USER_ID);

  if (typeof window !== "undefined") {
    localStorage.setItem("demoUserId", fallback);
  }

  return fallback;
}
