"use client";

import Link from "next/link";
import { Suspense, useEffect, useState } from "react";
import { useSearchParams } from "next/navigation";
import InvoiceForm from "./InvoiceForm";
import { ensureClientUserId } from "../../../lib/clientUser";

type InvoiceRecord = {
  id: number;
  customer_id: number | null;
  customer?: { id: number; name: string } | null;
  customer_name?: string | null;
  amount: number;
  description?: string | null;
};

export default function InvoicesPage() {
  return (
    <Suspense fallback={<div className="p-8 text-gray-600">Loading invoice workspace…</div>}>
      <InvoicesPageContent />
    </Suspense>
  );
}

function InvoicesPageContent() {
  const searchParams = useSearchParams();
  const preset = {
    customerId: searchParams.get("customerId"),
    taskId: searchParams.get("fromTask"),
    taskName: searchParams.get("taskName"),
    taskSeconds: searchParams.get("taskSeconds"),
  };

  const [invoices, setInvoices] = useState<InvoiceRecord[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [userId, setUserId] = useState<string | null>(null);

  useEffect(() => {
    let active = true;
    ensureClientUserId()
      .then(id => {
        if (active) setUserId(id);
      })
      .catch(() => {
        if (active) setError("Unable to resolve workspace user.");
      });
    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (!userId) return;
    setLoading(true);
    const qs = new URLSearchParams({ user_id: userId });
    fetch(`/api/invoices?${qs.toString()}`)
      .then(res => {
        if (!res.ok) throw new Error("Failed to load");
        return res.json();
      })
      .then(data => {
        setInvoices(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(() => {
        setError("Failed to load invoices");
        setLoading(false);
      });
  }, [userId]);

  async function handleAdd(invoice: {
    customerId: number;
    customerName: string;
    amount: number;
    description: string;
    reference: string;
    userId: string;
    lines: Array<{
      itemId: number | null;
      itemName: string;
      quantity: number;
      rate: number;
      total: number;
      project: string | null;
      note: string | null;
      source: string | null;
      taskRef: string | null;
    }>;
  }) {
    if (!invoice.userId) {
      setError("Workspace context missing for invoice.");
      return false;
    }
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/invoices", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          customer_id: invoice.customerId,
          amount: invoice.amount,
          description: invoice.description,
          reference: invoice.reference,
          lines: invoice.lines,
          user_id: invoice.userId,
        }),
      });
      if (!res.ok) throw new Error("Failed to add invoice");
      const newInvoice = await res.json();
      setInvoices(prev => [newInvoice, ...prev]);
      return true;
    } catch {
      setError("Failed to add invoice");
      return false;
    } finally {
      setLoading(false);
    }
  }

  const [editing, setEditing] = useState<number | null>(null);
  const [editData, setEditData] = useState<{ amount: number; description: string }>({ amount: 0, description: "" });

  function handleEdit(inv: InvoiceRecord) {
    setEditing(inv.id);
    setEditData({ amount: inv.amount, description: inv.description || "" });
  }

  async function handleUpdate(e: React.FormEvent) {
    e.preventDefault();
    if (!userId) {
      setError("Workspace context missing for update.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/invoices", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: editing, amount: editData.amount, description: editData.description, user_id: userId }),
      });
      if (!res.ok) throw new Error("Failed to update invoice");
      const updated = await res.json();
      setInvoices(prev => prev.map(i => (i.id === editing ? updated : i)));
      setEditing(null);
      setEditData({ amount: 0, description: "" });
    } catch {
      setError("Failed to update invoice");
    } finally {
      setLoading(false);
    }
  }

  async function handleDelete(id: number) {
    if (!userId) {
      setError("Workspace context missing for delete.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/invoices", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id, user_id: userId }),
      });
      if (!res.ok) throw new Error("Failed to delete invoice");
      setInvoices(prev => prev.filter(i => i.id !== id));
    } catch {
      setError("Failed to delete invoice");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="p-8 space-y-6">
      <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-2xl font-bold">Invoices</h1>
          <p className="text-gray-600">Pull time, photos, and inventory straight into polished invoices.</p>
        </div>
        <div className="flex gap-2">
          <Link href="/dashboard/tasks" className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-semibold text-slate-700 shadow-sm hover:bg-slate-50">View tasks</Link>
          <Link href="/dashboard/items" className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-semibold text-slate-700 shadow-sm hover:bg-slate-50">View inventory</Link>
        </div>
      </div>
      <InvoiceForm onAdd={handleAdd} preset={preset} />
      {loading && <div className="text-blue-600">Loading...</div>}
      {error && <div className="text-red-600">{error}</div>}
      <ul className="mt-4">
        {invoices.map((inv, i) => {
          const customerLabel = inv.customer?.name || inv.customer_name || (inv.customer_id ? `Customer #${inv.customer_id}` : "Customer");
          return (
            <li key={inv.id ?? i} className="border-b py-2 flex items-center gap-2">
              {editing === inv.id ? (
                <form onSubmit={handleUpdate} className="flex gap-2 flex-1 items-center">
                  <span className="font-semibold flex-1">{customerLabel}</span>
                  <input
                    className="border p-1 rounded w-32"
                    type="number"
                    min="0"
                    value={editData.amount}
                    onChange={e => setEditData(ed => ({ ...ed, amount: Number(e.target.value) }))}
                    required
                  />
                  <input
                    className="border p-1 rounded flex-1"
                    value={editData.description}
                    onChange={e => setEditData(ed => ({ ...ed, description: e.target.value }))}
                    placeholder="Description"
                  />
                  <button className="bg-green-600 text-white px-2 py-1 rounded" type="submit">Save</button>
                  <button className="bg-gray-400 text-white px-2 py-1 rounded" type="button" onClick={() => setEditing(null)}>Cancel</button>
                </form>
              ) : (
                <>
                  <span className="font-semibold">{customerLabel}</span> — R{inv.amount?.toFixed(2)}
                  {inv.description && <span className="ml-2 text-gray-600">({inv.description})</span>}
                  <button className="bg-yellow-500 text-white px-2 py-1 rounded ml-2" onClick={() => handleEdit(inv)}>Edit</button>
                  <button className="bg-red-600 text-white px-2 py-1 rounded ml-2" onClick={() => handleDelete(inv.id)}>Delete</button>
                </>
              )}
            </li>
          );
        })}
      </ul>
    </main>
  );
}
